   193	  (void)memset(pUnpackedBuf, 0, unpackedBufLen);
   194	  if (fapi_nr_p5_message_header_unpack(&pReadPackedMessage, NFAPI_HEADER_LENGTH, pMessageHeader, sizeof(fapi_message_header_t), 0)
